from flask import Flask, request, jsonify, send_file
from flask_sqlalchemy import SQLAlchemy
from flask_marshmallow import Marshmallow
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///videos.db'
app.config['UPLOAD_FOLDER'] = 'uploads/'
db = SQLAlchemy(app)
ma = Marshmallow(app)

class Video(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    title = db.Column(db.String(100), nullable=False)
    filename = db.Column(db.String(100), nullable=False)
    resolution = db.Column(db.String(20), nullable=False)

class VideoSchema(ma.SQLAlchemyAutoSchema):
    class Meta:
        model = Video

video_schema = VideoSchema()
videos_schema = VideoSchema(many=True)

@app.route('/upload', methods=['POST'])
def upload_video():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    filename = secure_filename(file.filename)
    resolution = request.form.get('resolution', '720p')
    file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
    new_video = Video(title=request.form['title'], filename=filename, resolution=resolution)
    db.session.add(new_video)
    db.session.commit()
    return video_schema.jsonify(new_video), 201

@app.route('/videos', methods=['GET'])
def get_videos():
    all_videos = Video.query.all()
    return videos_schema.jsonify(all_videos)

@app.route('/video/<int:id>', methods=['GET'])
def get_video(id):
    video = Video.query.get_or_404(id)
    return video_schema.jsonify(video)

@app.route('/video/play/<int:id>', methods=['GET'])
def play_video(id):
    video = Video.query.get_or_404(id)
    return send_file(os.path.join(app.config['UPLOAD_FOLDER'], video.filename), as_attachment=False)

@app.route('/video/pause', methods=['POST'])
def pause_video():
    # Placeholder for pause functionality
    return jsonify({'message': 'Video paused'}), 200

@app.route('/video/restart', methods=['POST'])
def restart_video():
    # Placeholder for restart functionality
    return jsonify({'message': 'Video restarted'}), 200

@app.route('/video/skip', methods=['POST'])
def skip_video():
    # Placeholder for skip functionality
    return jsonify({'message': 'Video skipped'}), 200

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)

