    db.session.commit()
    return jsonify({'message': 'Resolution changed successfully'}), 200

@app.route('/video/<int:video_id>/controls', methods=['POST'])
def control_video(video_id):
    action = request.json.get('action')
    if action not in ['pause', 'play', 'skip_forward', 'skip_backward']:
        return jsonify({'error': 'Invalid action'}), 400
    # Here you would implement the logic to control video playback
    return jsonify({'message': f'Video {action} action executed'}), 200

if __name__ == '__main__':
    if not os.path.exists(app.config['UPLOAD_FOLDER']):
