from flask import Flask, render_template, request, Response
from flask_socketio import SocketIO, emit
import cv2
import threading

app = Flask(__name__)
socketio = SocketIO(app)

video_stream = None
video_thread = None
is_streaming = False

def generate_frames():
    global video_stream
    while True:
        if video_stream is not None:
            success, frame = video_stream.read()
            if not success:
                break
            else:
                ret, buffer = cv2.imencode('.jpg', frame)
                frame = buffer.tobytes()
                yield (b'--frame\r\n'
                       b'Content-Type: image/jpeg\r\n\r\n' + frame + b'\r\n')

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/video_feed')
def video_feed():
    return Response(generate_frames(), mimetype='multipart/x-mixed-replace; boundary=frame')

@socketio.on('start_stream')
def start_stream(data):
    global video_stream, video_thread, is_streaming
    if not is_streaming:
        video_stream = cv2.VideoCapture(data['source'])
        is_streaming = True
        video_thread = threading.Thread(target=generate_frames)
        video_thread.start()
        emit('stream_started', {'status': 'streaming'})

@socketio.on('stop_stream')
def stop_stream():
    global video_stream, is_streaming
    if is_streaming:
        video_stream.release()
        is_streaming = False
        emit('stream_stopped', {'status': 'stopped'})

@socketio.on('pause_stream')
def pause_stream():
    global is_streaming
    is_streaming = False
    emit('stream_paused', {'status': 'paused'})

@socketio.on('resume_stream')
def resume_stream():
    global is_streaming
    is_streaming = True
    emit('stream_resumed', {'status': 'resumed'})

@socketio.on('seek_stream')
