import tkinter as tk
from tkinter import messagebox
import vlc
import os

class VideoPlayer:
    def __init__(self, master):
        self.master = master
        self.master.title("Video Streaming Player")
        self.media_player = None
        self.is_paused = False

        self.create_widgets()

    def create_widgets(self):
        self.play_button = tk.Button(self.master, text="Play", command=self.play_video)
        self.play_button.pack()

        self.pause_button = tk.Button(self.master, text="Pause", command=self.pause_video)
        self.pause_button.pack()

        self.stop_button = tk.Button(self.master, text="Stop", command=self.stop_video)
        self.stop_button.pack()

        self.rewind_button = tk.Button(self.master, text="Rewind", command=self.rewind_video)
        self.rewind_button.pack()

        self.forward_button = tk.Button(self.master, text="Forward", command=self.forward_video)
        self.forward_button.pack()

        self.video_path_entry = tk.Entry(self.master, width=50)
        self.video_path_entry.pack()
        self.video_path_entry.insert(0, "Enter video file path here")

    def play_video(self):
        video_path = self.video_path_entry.get()
        if os.path.exists(video_path):
            if self.media_player is None:
                self.media_player = vlc.MediaPlayer(video_path)
            self.media_player.play()
            self.is_paused = False
        else:
            messagebox.showerror("Error", "Video file not found.")

    def pause_video(self):
        if self.media_player:
            if self.is_paused:
                self.media_player.play()
                self.is_paused = False
            else:
                self.media_player.pause()
                self.is_paused = True

    def stop_video(self):
        if self.media_player:
            self.media_player.stop()
            self.is_paused = False

    def rewind_video(self):
        if self.media_player:
            current_time = self.media_player.get_time()
            self.media_player.set_time(max(0, current_time - 10000))  # Rewind 10 seconds

    def forward_video(self):
        if self.media_player:
            current_time = self.media_player.get_time()
            self.media_player.set_time(current_time + 10000)  # Forward 10 seconds

if __name__ == "__main__":
    root = tk.Tk()
    player = VideoPlayer(root)
    root.mainloop()

